#!/usr/bin/env python3
"""
DGX DEPLOY v19.34.239 — dynamic trigger_probability (always-on).

Idempotent: rewrites the two files from embedded gzip+base64 blobs,
runs the v239 pytest under .venv, then git commit && git push (REQUIRED —
the .bat restart runs `git checkout -- .` which wipes uncommitted work),
then restarts the backend via ./start_backend.sh --force.

Run on the DGX repo root:  .venv/bin/python /tmp/deploy_v19_34_239.py
"""
import base64, gzip, os, subprocess, sys

FILES = {
    'backend/services/enhanced_scanner.py': '',
    'backend/tests/test_v19_34_239_dynamic_trigger_prob.py': '',
}

ROOT = os.path.dirname(os.path.abspath(__file__))
# When run from /tmp, fall back to CWD as the repo root.
REPO = os.getcwd()

def main():
    if not os.path.isdir(os.path.join(REPO, "backend", "services")):
        print(f"[FATAL] not a repo root (no backend/services): {REPO}")
        sys.exit(1)
    for rel, b in FILES.items():
        dst = os.path.join(REPO, rel)
        os.makedirs(os.path.dirname(dst), exist_ok=True)
        data = gzip.decompress(base64.b64decode(b))
        with open(dst, "wb") as f:
            f.write(data)
        print(f"[WROTE] {rel} ({len(data)} bytes)")

    # Verify with pytest under the venv python actually running this.
    print("[TEST] running v239 pytest ...")
    r = subprocess.run(
        [sys.executable, "-m", "pytest",
         "backend/tests/test_v19_34_239_dynamic_trigger_prob.py", "-q"],
        cwd=REPO)
    if r.returncode != 0:
        print("[FATAL] pytest failed — aborting BEFORE commit/restart.")
        sys.exit(2)

    # Commit + push BEFORE restart (the .bat does git checkout -- .).
    subprocess.run(["git", "add",
                    "backend/services/enhanced_scanner.py",
                    "backend/tests/test_v19_34_239_dynamic_trigger_prob.py"],
                   cwd=REPO)
    c = subprocess.run(
        ["git", "commit", "-m",
         "v19.34.239 — dynamic trigger_probability via _apply_setup_context chokepoint"],
        cwd=REPO)
    if c.returncode != 0:
        print("[INFO] git commit no-op (already committed / clean) — continuing.")
    p = subprocess.run(["git", "push"], cwd=REPO)
    if p.returncode != 0:
        print("[WARN] git push failed — commit is LOCAL; push manually.")

    print("[RESTART] ./start_backend.sh --force")
    subprocess.run(["./start_backend.sh", "--force"], cwd=REPO)
    print("[DONE] v19.34.239 deployed.")

if __name__ == "__main__":
    main()
